'use strict';

// MODULES //

var bench = require( '@stdlib/bench' );
var uniform = require( '@stdlib/random/array/uniform' );
var randu = require( '@stdlib/random/base/randu' );
var discreteUniform = require( '@stdlib/random/array/discrete-uniform' );
var isObject = require( '@stdlib/assert/is-object' );
var isString = require( '@stdlib/assert/is-string' ).isPrimitive;
var Float64Array = require( '@stdlib/array/float64' );
var pkg = require( './../package.json' ).name;
var bartlettTest = require( './../lib' );


// MAIN //

bench( pkg, function benchmark( b ) {
	var result;
	var x;
	var y;
	var z;
	var i;

	x = uniform( 50, 0.0, 50.0 );
	y = uniform( 50, 10.0, 60.0 );
	z = uniform( 50, 20.0, 70.0 );

	b.tic();
	for ( i = 0; i < b.iterations; i++ ) {
		y[ i % y.length ] = ( randu()*50.0 ) + 10.0;
		result = bartlettTest( x, y, z );
		if ( typeof result !== 'object' ) {
			b.fail( 'should return an object' );
		}
	}
	b.toc();
	if ( !isObject( result ) ) {
		b.fail( 'should return an object' );
	}
	b.pass( 'benchmark finished' );
	b.end();
});

bench( pkg+'::groups', function benchmark( b ) {
	var result;
	var group;
	var vals;
	var len;
	var i;

	len = 150;
	group = discreteUniform( 150, 0, 2 );
	vals = new Float64Array( len );
	for ( i = 0; i < len; i++ ) {
		vals[ i ] = ( randu()*50.0 ) + ( 10.0*group[ i ] );
	}

	b.tic();
	for ( i = 0; i < b.iterations; i++ ) {
		vals[ i % vals.length ] = ( randu()*50.0 ) + ( 10.0*group[ i ] );
		result = bartlettTest( vals, {
			'groups': group
		});
		if ( typeof result !== 'object' ) {
			b.fail( 'should return an object' );
		}
	}
	b.toc();
	if ( !isObject( result ) ) {
		b.fail( 'should return an object' );
	}
	b.pass( 'benchmark finished' );
	b.end();
});

bench( pkg+':toString', function benchmark( b ) {
	var digits;
	var result;
	var output;
	var group;
	var vals;
	var len;
	var i;

	len = 100;
	group = discreteUniform( len, 0, 2 );
	vals = new Float64Array( len );
	for ( i = 0; i < len; i++ ) {
		vals[ i ] = ( randu()*50.0 ) + ( 10.0*group[ i ] );
	}
	result = bartlettTest( vals, {
		'groups': group
	});

	b.tic();
	for ( i = 0; i < b.iterations; i++ ) {
		digits = ( i % 8 ) + 1;
		output = result.toString({
			'digits': digits
		});
		if ( typeof output !== 'string' ) {
			b.fail( 'should return a string' );
		}
	}
	b.toc();
	if ( !isString( output ) ) {
		b.fail( 'should return a string' );
	}
	b.pass( 'benchmark finished' );
	b.end();
});
